"<td>MEASURES OF LENGTH.</td>",
"</tr>",
"<tr>",
"<td>The <b>MÈTRE</b>, the unit of length, is the ten-millionth part of a line drawn from the Pole to the Equator.</td>",
"</tr>",
"<tr>",
"<td>",
"<table>",
"<tr>",
"<td>1 Mètre</td> <td>=</td> <td>as above.</td>",
"</tr>",
"<tr>",
"<td>1 Décamètre</td> <td>=</td> <td>10</td> <td>mètres.</td>",
"</tr>",
"<tr>",
"<td>1 Hectomètre</td> <td>=</td> <td>100</td> <td>\"</td>",
"</tr>",
"<tr>",
"<td>1 Kilomètre</td> <td>=</td> <td>1000</td> <td>\"</td>",
"</tr>",
"<tr>",
"<td>1 Myriamètre</td> <td>=</td> <td>10,000</td> <td>\"</td>",
"</tr>",
"</table>",
"</td>",
"<td>",
"<table>",
"<tr>",
"<td> </td>",
"</tr>",
"<tr>",
"<td>1 Decimètre</td> <td>=</td> <td>1⁄10th</td> <td>of a mètre.</td>",
"</tr>",
"<tr>",
"<td>1 Centimètre</td> <td>=</td> <td>1⁄100th</td> <td>\"</td>",
"</tr>",
"<tr>",
"<td>1 Millimètre</td> <td>=</td> <td>1⁄1000th</td> <td>\"</td>",
"</tr>",
"<tr>",
"<td> </td>",
